/* =========================================================
   Vimium – Apple HIG Light Theme
   Inspired by macOS Ventura / Spotlight / Safari
   ========================================================= */

:root {
  /* --- Typography --- */
  --font: -apple-system, "SF Pro Text", "Helvetica Neue", sans-serif;
  --font-display: -apple-system, "SF Pro Display", "Helvetica Neue", sans-serif;

  --font-size:        15px;
  --font-size-title:  14px;
  --font-size-hints:  11px;
  --font-size-url:    12px;

  --font-weight:        400;
  --font-weight-medium: 500;
  --font-weight-bold:   600;

  /* --- Spacing --- */
  --padding:          4px;
  --padding-vomnibar: 6px 0;
  --radius-bar:       14px;
  --radius-item:      9px;
  --radius-hint:      5px;
  --radius-hud:       10px;

  /* --- Apple-style depth --- */
  --shadow:
    0 0 0 0.5px rgba(0, 0, 0, 0.10),
    0 4px 6px  rgba(0, 0, 0, 0.04),
    0 12px 40px rgba(0, 0, 0, 0.10),
    0 1px 1px  rgba(255, 255, 255, 0.95) inset;
  --blur: 40px;

  /* --- Color palette (macOS light) --- */
  --fg:          #1c1c1e;   /* Label */
  --fg-medium:   #48484a;   /* Secondary label */
  --fg-muted:    #8e8e93;   /* Tertiary label */
  --fg-url:      #636366;
  --fg-match:    #1c1c1e;

  --bg:           rgba(255, 255, 255, 0.85);
  --bg-secondary: rgba(242, 242, 247, 0.90);
  --bg-tertiary:  rgba(229, 229, 234, 0.80);

  --border:       rgba(0, 0, 0, 0.08);
  --border-inner: rgba(0, 0, 0, 0.05);
  --separator:    rgba(60, 60, 67, 0.12);

  /* --- Apple Blue accent --- */
  --accent:        #007aff;
  --accent-soft:   rgba(0, 122, 255, 0.10);
  --accent-mid:    rgba(0, 122, 255, 0.18);

  /* Selected state (Spotlight-like) */
  --bg-selected:   rgba(0, 122, 255, 0.10);
  --bg-hover:      rgba(0, 0, 0, 0.04);

  /* Hints */
  --fg-hints:      #1c1c1e;
  --bg-hints:      #fffffe;
}


/* ==========================================================
   VOMNIBAR  (Spotlight-style search bar)
   ========================================================== */

#vomnibar {
  background: var(--bg);
  -webkit-backdrop-filter: blur(var(--blur)) saturate(180%);
  backdrop-filter: blur(var(--blur)) saturate(180%);
  border: 0.5px solid var(--border);
  box-shadow: var(--shadow);
  border-radius: var(--radius-bar);
  overflow: hidden;

  /* Centered, constrained width */
  left: 50%;
  margin-left: -380px;
  max-width: 760px;
}

/* Input area */
#vomnibar #vomnibar-search-area,
#vomnibar input {
  background: transparent;
  border: none;
  box-shadow: none;
  color: var(--fg);
  font-family: var(--font-display);
  font-size: 17px;
  font-weight: var(--font-weight-medium);
  letter-spacing: -0.022em;
}

#vomnibar #vomnibar-search-area {
  padding: 16px 20px 16px 52px;
  position: relative;
  background: transparent;
}

/* Magnifier icon – Apple SF Symbols style path */
#vomnibar #vomnibar-search-area::before {
  content: "";
  position: absolute;
  top: 50%;
  left: 18px;
  transform: translateY(-50%);
  width: 20px;
  height: 20px;
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='none'><circle cx='10.5' cy='10.5' r='6.5' stroke='%238e8e93' stroke-width='1.8'/><path d='M15.5 15.5L20 20' stroke='%238e8e93' stroke-width='1.8' stroke-linecap='round'/></svg>");
  background-repeat: no-repeat;
  background-size: contain;
  pointer-events: none;
}

#vomnibar input {
  border: none;
  padding: var(--padding);
  outline: none;
  width: 100%;
}

#vomnibar input::placeholder {
  color: var(--fg-muted);
  font-weight: var(--font-weight);
}

.no-insert-text {
  display: none;
}

/* Divider between input and list */
#vomnibar ul {
  background: transparent;
  border-top: 0.5px solid var(--separator);
  margin: 0 10px;
  margin-bottom: 8px;
  padding: var(--padding-vomnibar);
  list-style: none;
}

/* Result row */
#vomnibar li {
  border-bottom: none;
  padding: 9px 12px;
  border-radius: var(--radius-item);
  cursor: pointer;
  transition: background 0.1s ease;
  margin-bottom: 1px;
}

#vomnibar li:hover {
  background: var(--bg-hover);
}

/* Top row: favicon + title */
#vomnibar li .top-half {
  padding: 0;
  display: flex;
  align-items: center;
  gap: 8px;
}

/* Bottom row: URL */
#vomnibar li .bottom-half {
  padding: 0;
  margin: 3px 0 0 0;
}

/* Source label */
#vomnibar li .source {
  color: var(--fg-muted);
  font-family: var(--font);
  font-size: 10px;
  font-weight: var(--font-weight-medium);
  text-transform: uppercase;
  letter-spacing: 0.07em;
}

/* Title */
#vomnibar li em,
#vomnibar li .title {
  color: var(--fg);
  font-family: var(--font);
  font-size: var(--font-size-title);
  font-weight: var(--font-weight-medium);
  letter-spacing: -0.014em;
  line-height: 1.4;
  font-style: normal;
}

/* URL */
#vomnibar li .url {
  color: var(--fg-url);
  font-family: var(--font);
  font-size: var(--font-size-url);
  font-weight: var(--font-weight);
  letter-spacing: -0.008em;
  opacity: 0.9;
}

/* Match highlight in title */
#vomnibar li .match {
  color: var(--accent);
  font-weight: var(--font-weight-bold);
}

#vomnibar li .title .match {
  color: var(--accent);
  font-weight: var(--font-weight-bold);
  background: var(--accent-soft);
  padding: 1px 4px;
  border-radius: 4px;
}

/* Selected row — Spotlight-like blue tint */
#vomnibar li.selected {
  background: var(--bg-selected);
  border-radius: var(--radius-item);
  outline: none;
}

#vomnibar li.selected .url {
  color: var(--fg-url);
}

#vomnibar li.selected .match {
  color: var(--accent);
}

#vomnibar li.selected .title {
  color: var(--fg-match);
}

#vomnibar li.selected .title .match {
  background: var(--accent-mid);
}


/* ==========================================================
   HINT MARKERS  (keyboard nav labels)
   ========================================================== */

#vimium-hint-marker-container div.internal-vimium-hint-marker,
#vimium-hint-marker-container div.vimiumHintMarker {
  background: var(--bg-hints);
  border: 0.5px solid rgba(0, 0, 0, 0.12);
  box-shadow:
    0 1px 0 rgba(255, 255, 255, 1) inset,
    0 2px 8px rgba(0, 0, 0, 0.12),
    0 0 0 0.5px rgba(0, 0, 0, 0.06);
  padding: 3px 6px;
  border-radius: var(--radius-hint);
}

#vimium-hint-marker-container div span {
  color: var(--fg-hints);
  font-family: var(--font);
  font-size: var(--font-size-hints);
  font-weight: var(--font-weight-bold);
  text-shadow: none;
  letter-spacing: 0.04em;
}

/* Typed-out (consumed) characters fade */
#vimium-hint-marker-container div > .matchingCharacter {
  color: var(--fg-muted);
  opacity: 0.35;
}

/* Remaining characters highlighted in Apple Blue */
#vimium-hint-marker-container div > .matchingCharacter ~ span {
  color: var(--accent);
}


/* ==========================================================
   HUD  (status bar / find mode)
   ========================================================== */

#hud-container {
  background: var(--bg);
  -webkit-backdrop-filter: blur(20px) saturate(180%);
  backdrop-filter: blur(20px) saturate(180%);
  border: 0.5px solid var(--border);
  box-shadow:
    0 2px 16px rgba(0, 0, 0, 0.08),
    0 0 0 0.5px rgba(255, 255, 255, 0.6) inset;
  border-radius: var(--radius-hud);
}

#hud-container span#hud-find-input,
#hud-container #hud {
  color: var(--fg);
  font-family: var(--font);
  font-size: 13px;
  font-weight: var(--font-weight);
  letter-spacing: -0.01em;
}

#hud-container .hud-find {
  background-color: transparent;
  border: none;
}

#hud-container #search-area {
  background-color: transparent;
  padding: 8px 12px;
}
